import React, { useState, useEffect } from 'react';
import DisplayStockData from './Stock';

function View() {
  const [symbols, setSymbols] = useState([]);
  const [stockData, setStockData] = useState({});

  useEffect(() => {
    const fetchData = async (symbol) => {
      const response = await fetch(`http://127.0.0.1:8000/${symbol}/`);
      const data = await response.json();
      setStockData((prevData) => ({ ...prevData, [symbol]: data }));
    };

    symbols.forEach((symbol) => fetchData(symbol));
  }, [symbols]);

  useEffect(() => {
    const updateStockData = (event) => {
      const data = JSON.parse(event.data);
      setStockData((prevData) => ({ ...prevData, [data.symbol]: data }));
    };

    const sockets = symbols.map((symbol) => {
      const socket = new WebSocket(`ws://127.0.0.1:8000/ws/stock/${symbol}/`);
      socket.onmessage = updateStockData;
      return socket;
    });

    return () => {
      sockets.forEach((socket) => socket.close());
    };
  }, [symbols]);

  const handleAddStock = (symbol) => {
    if (symbols.length < 15 && !symbols.includes(symbol)) {
      setSymbols([...symbols, symbol]);
    }
  };

  const handleRemoveStock = (symbol) => {
    setSymbols(symbols.filter((s) => s !== symbol));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    const symbol = event.target.symbol.value;
    event.target.symbol.value = '';
    handleAddStock(symbol);
  };
}
export default View;
